3	const readStdin = async (): Promise<string> => {
4	  const chunks: Buffer[] = [];
5	  for await (const chunk of process.stdin) {
6	    chunks.push(chunk as Buffer);
7	  }
8	  return Buffer.concat(chunks).toString("utf8");
9	};
10	
11	const quotedItems = (steps: Step[]): Item[] =>
12	  steps.flatMap((step) => (step.op === "quote" ? step.items : []));
13	
14	const validateScenario = (scenario: Scenario): void => {
15	  const unknown = quotedItems(scenario.steps).find((item) => !isKnownItemType(item.type));
16	  if (unknown !== undefined) {
17	    throw new Error(`unknown item type: '${unknown.type}'`);
18	  }
19	};
20	
21	const main = async (): Promise<void> => {
22	  const input = await readStdin();
23	  const scenario = JSON.parse(input) as Scenario;
24	  validateScenario(scenario);
25	  const result = runScenario(scenario);
26	  process.stdout.write(JSON.stringify(result));
27	};
28	
29	main().catch((error: unknown) => {
30	  const message = error instanceof Error ? error.message : String(error);
31	  process.stderr.write(`${message}\n`);
32	  process.exit(1);
33	});
